#include <iostream>
#include <string>
#include <map>

using namespace std;

class TrieNode {
public:
    map<char, TrieNode*> children;
};

class Trie {
public:
    TrieNode* insert(TrieNode* root, string word) {
        for (int i = 0; i < word.length(); i++) {
            if (root->children.find(word[i]) == root->children.end()) {
                root->children[word[i]] = new TrieNode();
            }
            root = root->children[word[i]];
        }
        root->children['#'] = NULL;
        return root;
    }
};

int main() {
    Trie t;
    string word;
    while (cin >> word) {
        t.insert(NULL, word);
    }
    return 0;
}
